FUNCTION CalculateTotalDelay(packet, path)
BEGIN
 totalDelay = 0

 FOR EACH router IN path DO
 // Processing delay
 procDelay = router.processingTime

 // Queuing delay (depends on congestion)
 queueDelay = router.queueWaitingTime(packet)

 // Transmission delay
 transDelay = packet.size / router.linkBandwidth

 // Propagation delay
 propDelay = router.linkLength / router.signalSpeed

 // Add to total
 totalDelay = totalDelay + procDelay + queueDelay + transDelay + propDelay
 END FOR

 RETURN totalDelay
END FUNCTION

// Example calculation
// Given: 3 routers, packet size = 1000 bytes, link bandwidth = 1 Mbps
// Processing: 0.001s each, Queue: varies, Prop: 0.002s per link
